var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"……이대로는 안돼!","JPN":"これではダメよ！","ENG":"...This will not do!","TWN":"……這樣不行！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"이런 건 참신하지 않잖아! 누가 이런 걸 재밌다고 하겠어!","JPN":"こんなの斬新じゃないわ！　誰も面白いとは思わない！","ENG":"It's not original at all! Nobody's going to find this entertaining!","TWN":"一點新意都沒有！誰會覺得好看？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ACTING_NPC_GEASS_STAFF","text":{"KOREA":"아니, 부장! 갑자기 왜 그러는 거예요?","JPN":"そんな。部長、急にどうしたんですか？","ENG":"W-wait! Why are you acting like this all of a sudden?","TWN":"社長！為何突然這麼說？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ACTING_NPC_GEASS_STAFF","text":{"KOREA":"내일이 연극 상연인데, 이제와서 대본을 바꾸자는 게 말이 돼요!?","JPN":"上演は明日だっていうのに、\\nどうして今になって台本を変えるなんて言い出したんですか！？","ENG":"Tomorrow is the opening night of our play! You can't change the script now!","TWN":"明天就是正式演出，怎麼可以現在才說要修改劇本！？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"부실이 소란스럽군요, 무슨 일이죠?","JPN":"騒がしいですね、いかがなさいましたか？","ENG":"What’s going on here?","TWN":"怎麼吵吵鬧鬧的，發生什麼事了嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"아아, 오셨군요, 란체스터 회장님!","JPN":"ああ、来てくれたのですね。ランチェスター会長！","ENG":"Oh, you're here, Ms. Lanchester!","TWN":"蘭賈斯特會長來啦！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"역시 이 배역을 소화할 수 있는 사람은 회장님 밖에 없어요!","JPN":"やはりこの役を演じることができるのは、会長しかいませんわ！","ENG":"You're the only one who can play this role!","TWN":"果然只有會長是演出這個角色的不二人選！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"배역……? 자세한 설명을 부탁드리죠.","JPN":"役……？　詳しい説明をお願いします。","ENG":"Role...? Could you elaborate?","TWN":"角色……？你可以說清楚一點嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……그러니까 회장한테 배역을 맡기고 싶다고?","JPN":"……つまり、会長に書き換えた台本に登場する役を演じてほしいと？","ENG":"...So you want Yen to be a part of the play?","TWN":"……意思是，你想請會長演出？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"연극이 내일인데, 이렇게 막 스토리를 바꿔도 괜찮은 거야?","JPN":"明日が上演なのに、こんな急に展開を変えていいの？","ENG":"The play's tomorrow. Are you sure it's okay to change the story now?","TWN":"明天就要正式演出，這樣改劇本沒問題嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아무리 회장이라고 해도 갑자기 배역을 떠맡는 건 무리라고 생각하는데.","JPN":"いくら会長とはいえ、急に役を引き受けるのは無理だと思うけど……","ENG":"Even for Yen, I think it's too sudden for her to just take on a role.","TWN":"就算會長再怎麼厲害，突然要她演戲也太為難她。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ACTING_NPC_GEASS_STAFF","text":{"KOREA":"그러니까요! 저희도 갑자기 부장이 왜 말도 안되는 요구를 하는지 모르겠어요!","JPN":"そうなんですよ！\\n私たちもどうして部長が急に無茶を言いだしたのかわからないんです！","ENG":"That's what I've been telling her! We don't understand what she's trying to do!","TWN":"就是說啊！我們也無法理解社長為何提出這種不合理的要求！"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"흥, 너희들 뭘 모르네.","JPN":"ふん。あなたたちはわかってない。","ENG":"Hmph! What a bunch of amateurs.","TWN":"哼！你們懂什麼！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"이해하기도 어렵고, 고리타분한 고전 연극 같은 건 진작에 유행이 지났어.","JPN":"理解するのが難しいせいで、\\n古臭い古典演劇なんかとっくに時代遅れになっちゃったの。","ENG":"Classic plays with complicated and old-fashioned plots are a thing of the past now.","TWN":"這種難懂又老掉牙的劇本早就過時了！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"요즘은 직관적이고 화려한 연출을 보여 줄 수 있는 연극이 트렌드라고!","JPN":"今は直感的で華やかな演出を盛り込んだ演劇がトレンドなのよ！","ENG":"These days, intuitive and flashy performances are trending!","TWN":"最近流行的是暴力美學！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ACTING_NPC_GEASS_STAFF","text":{"KOREA":"그…… 부장이 말하는 이해하기 어렵고 고리타분한 대본, 부장이 직접 썼잖아요.","JPN":"その……、部長の言う理解しづらくて古臭い台本は、\\n部長自ら書き下ろしたものなんですが……","ENG":"Ergh... But you're the one who wrote that complicated and old-fashioned story.","TWN":"什……社長你說的難懂又老掉牙的劇本，是你自己寫的欸！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"제발요! 란체스터 회장님! 저희 무대에서 회장님의 검술 실력을 꼭 보여주세요!","JPN":"お願いです、ランチェスター会長！\\nどうか私たちの舞台で会長の剣術を披露してください！","ENG":"Please, Ms. Lanchester! Show everyone your brilliant sword skills up on stage!","TWN":"拜託你！蘭賈斯特會長！請在我們的舞台上展現你的劍術實力！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"보여주는 것만이라면 어렵지 않지만…….","JPN":"披露するだけなら難しくはありませんが……","ENG":"I don't see why not, but...","TWN":"要施展劍術是不困難……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아무리 합을 맞추고 진행한다고 해도, 검을 다루는 건 위험한 일입니다.","JPN":"事前に打ち合わせをするとしても、剣を扱うのはとても危険なことです。","ENG":"Even if everything is choreographed, handling a real sword on stage is dangerous.","TWN":"不過就算我願意配合你們，但畢竟刀劍無眼，還是有危險性的。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"상대 연기자 또한 비등한 실력을 갖추지 않으면 힘들겠군요.","JPN":"相手の役者さんも同じぐらいの実力がないと厳しいと思います。","ENG":"I would need the other actor to be also skilled with swords in order for this to work.","TWN":"若是對方和我實力不相當，會有點麻煩。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"혹시 연극부에도 무예를 배우신 분이 있을까요?","JPN":"演劇部に武芸を身につけていらっしゃる方はいますか？","ENG":"Is there anyone in the theater club who is good with a sword?","TWN":"請問戲劇部裡有人學過武術嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"으으, 그런 사람은…….","JPN":"えっと……それが……","ENG":"Um... I don't think there is...","TWN":"呃，學過武術嗎……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};